      clk_i     => clk_i,
      rst_i     => rst_i,
      vld_i   => vld_i,
      rdy_o   => rdy_o,
      dat_i  => dat_i,
      vld_o  => vld_o,
      rdy_i  => rdy_i,
      dat_o => dat_o
