        wait until rising_edge(clk_i);
        vld_i <= '0';
        assert rdy_o = '1' or not handle_rdy_g report "###ERROR###: rdy_o went low unexpectedly" severity error;
      end loop;
    end loop;
    if done /= true then
      wait until done = true;
    end if;

    -- Streaming	
