      wait until rising_edge(clk_i);
      for outDel in 0 to 10 loop
        for val in 1 to 4 loop
          vld_i  <= '1';
          dat_i <= std_logic_vector(to_unsigned(val, width_g));
          wait until rising_edge(clk_i) and rdy_o = '1';
        end loop;
        vld_i <= '0';
        wait for 1 us;
        wait until rising_edge(clk_i);
